<template><div class="workspace-page"><section class="page-intro"><div><p>每日有效指标</p><h2>指标趋势</h2><span>同日同指标优先采用机构报告；否则采用当天最后一次自测。</span></div></section><el-card shadow="never"><div class="filter-row"><label class="filter-field"><span class="filter-field-label">成员</span><el-select v-model="ownerId"><el-option label="本人" :value="null"/><el-option v-for="r in authorizedFriends" :key="r.friend_user_id" :label="r.friend_user?.username||r.relation_name" :value="r.friend_user_id"/></el-select></label><label class="filter-field"><span class="filter-field-label">指标</span><el-select v-model="indicatorId" filterable><el-option v-for="i in indicators" :key="i.id" :label="`${i.name}（${i.unit||'-'}）`" :value="i.id"/></el-select></label><el-button type="primary" :loading="loading" @click="load">查询</el-button></div></el-card>
<section class="metric-grid"><article v-for="m in metrics" :key="m.label" class="metric-card"><div><small>{{m.label}}</small><strong>{{m.value}}</strong><p>{{unit}}</p></div></article></section><el-card shadow="never"><div ref="chartEl" style="height:420px"/><el-table :data="points" empty-text="暂无趋势数据"><el-table-column prop="date" label="日期"/><el-table-column label="有效值"><template #default="s">{{s.row.value}} {{unit}}</template></el-table-column><el-table-column label="来源"><template #default="s"><el-tag :type="s.row.source==='institution_report'?'success':'info'">{{s.row.source==='institution_report'?'机构报告':'用户自测'}}</el-tag></template></el-table-column></el-table></el-card></div></template>
<script setup>import{computed,nextTick,onBeforeUnmount,onMounted,ref,watch}from"vue";import{fetchFriends}from"../api/friends";import{fetchTrend}from"../api/health";import{fetchIndicatorDicts}from"../api/indicators";import{initTrendChart}from"../utils/echartsRuntime";const indicators=ref([]),friends=ref([]),ownerId=ref(null),indicatorId=ref(null),points=ref([]),summary=ref({}),loading=ref(false),chartEl=ref(null);let chart;const authorizedFriends=computed(()=>friends.value.filter(r=>r.auth_status));const currentIndicator=computed(()=>indicators.value.find(i=>i.id===indicatorId.value));const unit=computed(()=>currentIndicator.value?.unit||"");const metrics=computed(()=>[{label:"最新值",value:summary.value.latest??"-"},{label:"最高值",value:summary.value.highest??"-"},{label:"最低值",value:summary.value.lowest??"-"},{label:"有效记录",value:summary.value.count??0}]);function render(){if(!chartEl.value)return;chart ||= initTrendChart(chartEl.value);chart.setOption({tooltip:{trigger:"axis"},grid:{left:50,right:28,top:30,bottom:45},xAxis:{type:"category",data:points.value.map(p=>p.date)},yAxis:{type:"value",name:unit.value},series:[{type:"line",smooth:true,data:points.value.map(p=>({value:p.value,itemStyle:{color:p.source==='institution_report'?'#2f855a':'#3b82f6'}})),symbolSize:9}]},true)}async function load(){if(!indicatorId.value)return;loading.value=true;try{const{data}=await fetchTrend(indicatorId.value,ownerId.value?{owner_id:ownerId.value}:{});points.value=data.points||[];summary.value=data.summary||{};await nextTick();render()}finally{loading.value=false}}watch([ownerId,indicatorId],load);onMounted(async()=>{const[a,b]=await Promise.all([fetchIndicatorDicts(),fetchFriends()]);indicators.value=a.data.items||[];friends.value=b.data.items||[];indicatorId.value=indicators.value.find(i=>i.allow_self_measurement)?.id||indicators.value[0]?.id;window.addEventListener("resize",()=>chart?.resize())});onBeforeUnmount(()=>chart?.dispose());</script>
